import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> framework -> {pkg: (requested, resolved)}
def build_lookup(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        result[name] = {}
        for fw in proj['frameworks']:
            pkgs = {}
            for p in fw['topLevelPackages']:
                pkgs[p['id']] = (p['requestedVersion'], p['resolvedVersion'])
            result[name][fw['framework']] = pkgs
    return result

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []

for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bp = b.get(proj,{}).get(fw,{})
        ap = a.get(proj,{}).get(fw,{})
        all_pkgs = sorted(set(list(bp.keys()) + list(ap.keys())))
        for pkg in all_pkgs:
            bv = bp.get(pkg)
            av = ap.get(pkg)
            if bv and av:
                if bv[1] != av[1]:
                    changes.append((proj, fw, pkg, bv[1], av[1], 'Aligned to highest version'))
                elif bv[0] != av[0]:
                    changes.append((proj, fw, pkg, bv[1], av[1], 'Version source changed (property inlined)'))
                else:
                    unchanged.append((proj, fw, pkg, av[1]))
            elif bv and not av:
                changes.append((proj, fw, pkg, bv[1], '-', 'Removed'))
            elif av and not bv:
                changes.append((proj, fw, pkg, '-', av[1], 'Added'))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<20} {'TFM':<10} {'Package':<50} {'Before':<12} {'After':<12} Status')
    for c in changes:
        print(f'{c[0]:<20} {c[1]:<10} {c[2]:<50} {c[3]:<12} {c[4]:<12} {c[5]}')
else:
    print('None')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<20} {'TFM':<10} {'Package':<50} {'Version':<12}')
for u in unchanged:
    print(f'{u[0]:<20} {u[1]:<10} {u[2]:<50} {u[3]:<12}')
